(window.webpackJsonp=window.webpackJsonp||[]).push([[307],{934:function(n,e){n.exports="\x3c!-- \ntitle: 08-实战\nsort: \n--\x3e \n\n> Login.js\n\n```js\nimport React, { useState } from 'react'\nimport { useHistory } from 'react-router-dom'\nimport { Form, Input, Button } from 'antd'\nimport axios from 'axios'\n\nconst FormItem = Form.Item;\n\nexport default function Login() {\n\n  const [name, setName] = useState('')\n  const [pwd, setPwd] = useState('')\n  const history = useHistory();\n\n  return <Form className=\"login-form\">\n    <FormItem>\n      <h1>React Login</h1>\n    </FormItem>\n    <FormItem>\n      <Input placeholder=\"User Name\" maxLength={5} onChange={(event) => {\n        setName(event.target.value)\n      }} />\n    </FormItem>\n    <FormItem>\n      <Input placeholder=\"Password\" maxLength={5} type=\"password\" onChange={(event) => {\n        setPwd(event.target.value)\n      }} />\n    </FormItem>\n    <FormItem>\n      <label>{name}-{pwd}</label>\n    </FormItem>\n    <FormItem>\n      <Button type=\"primary\" onClick={() => {\n        login(name, pwd).then((response) => {\n          let res = response.data;\n          if (res.code === 0) {\n            history.push('/home');\n          }\n        }, () => console.log(\"Login Error\")\n        )\n      }}>\n        登录</Button>\n    </FormItem>\n  </Form>\n}\n\nfunction login(name, pwd) {\n  return axios.get(\"/login.json\", {\n    params: {\n      name, pwd\n    }\n  })\n}\n```\n\n> Home.js\n\n```js\nimport { React, useEffect, useState } from 'react'\nimport axios from 'axios'\nimport { Link } from 'react-router-dom'\nimport { Table } from 'antd'\nimport './home.scss'\n\nexport default function Home() {\n\n  const [data, setData] = useState([]);\n  const [index, setIndex] = useState(0);\n  const columns = [\n    {\n      title: 'Area',\n      dataIndex: 'area'\n    }, {\n      title: 'Distribute',\n      dataIndex: 'distri'\n    }, {\n      title: 'State',\n      dataIndex: 'state'\n    }, {\n      title: 'Info',\n      dataIndex: 'info'\n    }, {\n      title: 'Active',\n      dataIndex: 'active'\n    }\n  ];\n\n  useEffect(() => {\n    axios.get('/data.json').then((response) => {\n      const res = response.data;\n      if (res.code == 0) {\n        setData(res.data);\n      }\n    })\n  }, []);\n\n  return <div className=\"home\">\n    <h1>React Report</h1>\n    <div className=\"wrap\">\n      <div className=\"nav\">\n        <a className={index == 0 ? \"checked\" : \"unchecked\"} onClick={() => setIndex(0)}>Dynamic</a>\n        <a className={index == 1 ? \"checked\" : \"unchecked\"} onClick={() => setIndex(1)}>Map</a>\n        <a className={index == 2 ? \"checked\" : \"unchecked\"} onClick={() => setIndex(2)}>Trend</a>\n        <a className={index == 3 ? \"checked\" : \"unchecked\"} onClick={() => setIndex(3)}>Report</a>\n      </div>\n      <p>Don't Trust.</p>\n      <Table\n        pagination={false}\n        columns={columns}\n        dataSource={data} />\n      <Link to=\"/\" className=\"nav-link\">Go Back</Link>\n    </div>\n  </div>\n}\n```\n\n"}}]);